
$c-red: #b03040;
$c-red-dim: #701020;
$c-gold: #e8be58;
$c-text: #ffe8ec;
$c-sub: #a07080;

.miaoxuan-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 8px;
}

.card {
  background: rgba(30, 8, 14, 0.4);
  border: 1px solid rgba($c-red, 0.2);
  border-radius: 6px;
  padding: 10px;
}

.section-title {
  display: flex;
  align-items: center;
  gap: 8px;
  color: $c-red;
  font-size: 13px;
  margin-bottom: 8px;
  font-weight: 600;
  .decor-line {
    flex: 1;
    height: 1px;
    background: linear-gradient(to right, transparent, rgba($c-red, 0.4), transparent);
  }
}

.stat-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 4px 0;
  font-size: 12px;
}
.stat-label {
  width: 60px;
  color: $c-sub;
}
.stat-track {
  flex: 1;
  height: 8px;
  background: rgba($c-red-dim, 0.25);
  border-radius: 4px;
  overflow: hidden;
}
.stat-fill {
  height: 100%;
  transition: width 0.5s;
  &.despair {
    background: linear-gradient(to right, $c-red-dim, $c-red);
  }
  &.pressure {
    background: linear-gradient(to right, #805020, $c-gold);
  }
}
.stat-val {
  width: 30px;
  text-align: right;
  color: $c-text;
}

.actions {
  margin-top: 10px;
}
.action-btn {
  width: 100%;
  padding: 8px;
  background: rgba($c-red, 0.15);
  border: 1px solid rgba($c-red, 0.35);
  color: $c-text;
  border-radius: 4px;
  cursor: pointer;
  font-size: 12px;
  transition: all 0.2s;
  &:hover:not(:disabled) {
    background: rgba($c-red, 0.25);
  }
  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

.unread-event {
  margin-top: 10px;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 8px;
  background: rgba($c-gold, 0.12);
  border-left: 2px solid $c-gold;
  border-radius: 3px;
}
.unread-dot {
  width: 8px;
  height: 8px;
  background: $c-gold;
  border-radius: 50%;
  animation: blink 1.5s infinite;
}
@keyframes blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}
.unread-label {
  color: $c-gold;
  font-size: 12px;
  flex: 1;
}
.unread-view-btn {
  background: rgba($c-gold, 0.2);
  border: 1px solid rgba($c-gold, 0.4);
  color: $c-gold;
  padding: 3px 8px;
  border-radius: 3px;
  font-size: 11px;
  cursor: pointer;
}

.thought {
  padding: 8px;
  background: rgba($c-red-dim, 0.2);
  border-radius: 4px;
  color: $c-text;
  font-size: 12px;
  line-height: 1.6;
  font-style: italic;
}
