
// ── 神魂空间角色选择浮层（非 scoped，因 Teleport 到 body） ──
.soul-picker-mask {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.75);
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(4px);
}
.soul-picker-dialog {
  min-width: 280px;
  background: linear-gradient(170deg, #1a0a10 0%, #0c0406 100%);
  border: 1px solid rgba(192, 48, 80, 0.4);
  border-radius: 10px;
  padding: 20px;
  box-shadow: 0 8px 40px rgba(0, 0, 0, 0.6);
}
.soul-picker-title {
  color: #ffe8ec;
  font-size: 16px;
  font-weight: 600;
  text-align: center;
  margin-bottom: 14px;
}
.soul-picker-opt {
  display: block;
  width: 100%;
  padding: 12px;
  margin-bottom: 10px;
  background: rgba(192, 48, 80, 0.15);
  border: 1px solid rgba(192, 48, 80, 0.35);
  border-radius: 6px;
  color: #ffe8ec;
  cursor: pointer;
  text-align: left;
  transition: all 0.2s;
  &:hover {
    background: rgba(192, 48, 80, 0.3);
  }
  &.luo {
    background: rgba(211, 108, 134, 0.15);
    border-color: rgba(211, 108, 134, 0.4);
    &:hover {
      background: rgba(211, 108, 134, 0.3);
    }
  }
}
.soul-picker-name {
  font-size: 14px;
  font-weight: 600;
}
.soul-picker-sub {
  font-size: 11px;
  color: #a07080;
  margin-top: 2px;
}
.soul-picker-cancel {
  width: 100%;
  padding: 8px;
  background: transparent;
  border: 1px solid rgba(160, 112, 128, 0.3);
  color: #a07080;
  border-radius: 4px;
  cursor: pointer;
  font-size: 12px;
  margin-top: 4px;
  &:hover {
    color: #ffe8ec;
  }
}
